1	/**
2	 * Markdown → block tree. Line-based, block-level only (design.md D1):
3	 * we segment and derive hierarchy; we never interpret-and-reprint.
4	 *
5	 * Dialect: Obsidian's pragmatic block markdown, not strict CommonMark.
6	 * Known deliberate simplifications (corpus tests guard the consequences):
7	 * - no lazy continuation lines (a column-0 line after a list item starts a
8	 *   new top-level paragraph);
9	 * - indented (4-space) code blocks at top level parse as paragraphs — the
10	 *   bytes still round-trip, only the node kind differs;
11	 * - a blockquote is a contiguous run of `>` lines.
12	 */
13	
14	import type { ListStyle, OutlineDoc, OutlineNode } from './model';
15	import { makeNode } from './model';
16	import { listAttachesTo } from './rules';
17	
18	const TAB_WIDTH = 4;
19	
20	export function indentWidth(line: string): number {
21	  let width = 0;
22	  for (const ch of line) {
23	    if (ch === ' ') width += 1;
24	    else if (ch === '\t') width += TAB_WIDTH - (width % TAB_WIDTH);
25	    else break;
26	  }
27	  return width;
28	}
29	
30	const isBlank = (line: string): boolean => line.trim() === '';
31	
32	const ATX_RE = /^ {0,3}(#{1,6})(?:[ \t]|$)/;
33	const FENCE_OPEN_RE = /^([ \t]*)(`{3,}|~{3,})/;
34	const LIST_ITEM_RE = /^([ \t]*)([-+*]|\d{1,9}[.)])(?:[ \t]+|$)/;
35	const QUOTE_RE = /^ {0,3}>/;
36	const CALLOUT_RE = /^ {0,3}>\s*\[!/;
37	const HR_RE = /^ {0,3}(?:(?:\* *){3,}|(?:- *){3,}|(?:_ *){3,})$/;
38	const SETEXT_RE = /^ {0,3}(=+|-+)[ \t]*$/;
39	const TABLE_DELIM_RE = /^[ \t]*\|?[ \t:|-]*-[ \t:|-]*\|?[ \t]*$/;
40	const HTML_OPEN_RE = /^ {0,3}<[a-zA-Z!/]/;
41	
42	function parseListMarker(line: string): { style: ListStyle; contentCol: number } | undefined {
43	  const match = LIST_ITEM_RE.exec(line);
44	  if (!match) return undefined;
45	  const [, indentText, marker] = match as unknown as [string, string, string];
46	  const indent = indentWidth(indentText);
47	  const style: ListStyle =
48	    marker === '-' || marker === '*' || marker === '+'
49	      ? { type: 'bullet', marker }
50	      : {
51	          type: 'ordered',
52	          number: parseInt(marker, 10),
53	          delimiter: marker.endsWith(')') ? ')' : '.',
54	        };
55	  // Content column: marker end + one space, in expanded-tab columns.
56	  const contentCol = indent + marker.length + 1;
57	  return { style, contentCol };
58	}
59	
60	/** A flat block produced by segmentation, before hierarchy derivation. */
61	interface Block {
62	  kind: OutlineNode['kind'];
63	  indent: number;
64	  contentCol: number;
65	  lines: string[];
66	  gap: string[];
67	  level?: number;
68	  setext?: boolean;
69	  listStyle?: ListStyle;
70	}
71	
72	function looksLikeTable(lines: readonly string[], i: number): boolean {
73	  const line = lines[i];
74	  const next = lines[i + 1];
75	  return (
76	    line !== undefined &&
77	    next !== undefined &&
78	    line.includes('|') &&
79	    !isBlank(line) &&
80	    TABLE_DELIM_RE.test(next) &&
81	    next.includes('-')
82	  );
83	}
84	
85	/** Would this line terminate an open paragraph by starting another block? */
86	function startsNewBlock(lines: readonly string[], i: number): boolean {
87	  const line = lines[i]!;
88	  return (
89	    ATX_RE.test(line) ||
90	    FENCE_OPEN_RE.test(line) ||
91	    LIST_ITEM_RE.test(line) ||
92	    QUOTE_RE.test(line) ||
93	    HR_RE.test(line) ||
94	    looksLikeTable(lines, i)
95	  );
96	}
97	
98	function segment(lines: readonly string[], start: number): Block[] {
99	  const blocks: Block[] = [];
100	  let preambleGapSink: string[] | undefined;
101	  let i = start;
102	
103	  const gapSink = (): string[] => {
104	    const last = blocks[blocks.length - 1];
105	    if (last) return last.gap;
106	    preambleGapSink ??= [];
107	    return preambleGapSink;
108	  };
109	
110	  while (i < lines.length) {
111	    const line = lines[i]!;
112	
113	    // Trailing empty segment from a final newline, and blank lines generally.
114	    if (isBlank(line) && !(i === lines.length - 1 && line === '' && blocks.length === 0)) {
115	      gapSink().push(line);
116	      i++;
117	      continue;
118	    }
119	    if (i === lines.length - 1 && line === '') {
120	      // Document ends with a newline and no content yet.
121	      gapSink().push(line);
122	      i++;
123	      continue;
124	    }
125	
126	    const indent = indentWidth(line);
127	
128	    // Fenced code block.
129	    const fence = FENCE_OPEN_RE.exec(line);
130	    if (fence) {
131	      const fenceChars = fence[2]!;
132	      const closeRe = new RegExp(`^[ \\t]*${fenceChars[0] === '`' ? '`' : '~'}{${fenceChars.length},}[ \\t]*$`);
133	      const block: Block = { kind: 'code', indent, contentCol: indent, lines: [line], gap: [] };
134	      i++;
135	      while (i < lines.length) {
136	        block.lines.push(lines[i]!);
137	        if (closeRe.test(lines[i]!)) {
138	          i++;
139	          break;
140	        }
141	        i++;
142	      }
143	      blocks.push(block);
144	      continue;
145	    }
146	
147	    // ATX heading.
148	    const atx = ATX_RE.exec(line);
149	    if (atx) {
150	      blocks.push({
151	        kind: 'heading',
152	        indent: 0,
153	        contentCol: 0,
154	        level: atx[1]!.length,
155	        lines: [line],
156	        gap: [],
157	      });
158	      i++;
159	      continue;
160	    }
161	
162	    // Blockquote / callout.
163	    if (QUOTE_RE.test(line)) {
164	      const kind = CALLOUT_RE.test(line) ? 'callout' : 'quote';
165	      const block: Block = { kind, indent, contentCol: indent, lines: [], gap: [] };
166	      while (i < lines.length && QUOTE_RE.test(lines[i]!)) {
167	        block.lines.push(lines[i]!);
168	        i++;
169	      }
170	      blocks.push(block);
171	      continue;
172	    }
173	
174	    // Thematic break (checked before list: `- - -` etc).
175	    if (HR_RE.test(line)) {
176	      blocks.push({ kind: 'hr', indent, contentCol: indent, lines: [line], gap: [] });
177	      i++;
178	      continue;
179	    }
180	
181	    // Table.
182	    if (looksLikeTable(lines, i)) {
183	      const block: Block = { kind: 'table', indent, contentCol: indent, lines: [], gap: [] };
184	      while (i < lines.length && !isBlank(lines[i]!) && lines[i]!.includes('|')) {
185	        block.lines.push(lines[i]!);
186	        i++;
187	      }
188	      blocks.push(block);
189	      continue;
190	    }
191	
192	    // List item (marker line + immediate continuation lines).
193	    const marker = parseListMarker(line);
194	    if (marker) {
195	      const block: Block = {
196	        kind: 'list-item',
197	        indent,
198	        contentCol: marker.contentCol,
199	        listStyle: marker.style,
200	        lines: [line],
201	        gap: [],
202	      };
203	      i++;
204	      // Continuation: non-blank lines indented to the content column that do
205	      // not start a nested block themselves (multiline nodes).
206	      while (
207	        i < lines.length &&
208	        !isBlank(lines[i]!) &&
209	        indentWidth(lines[i]!) >= marker.contentCol &&
210	        !LIST_ITEM_RE.test(lines[i]!) &&
211	        !FENCE_OPEN_RE.test(lines[i]!) &&
212	        !QUOTE_RE.test(lines[i]!) &&
213	        !looksLikeTable(lines, i)
214	      ) {
215	        block.lines.push(lines[i]!);
216	        i++;
217	      }
218	      blocks.push(block);
219	      continue;
220	    }
221	
222	    // HTML block.
223	    if (HTML_OPEN_RE.test(line)) {
224	      const block: Block = { kind: 'html', indent, contentCol: indent, lines: [], gap: [] };
225	      while (i < lines.length && !isBlank(lines[i]!)) {
226	        block.lines.push(lines[i]!);
227	        i++;
228	      }
229	      blocks.push(block);
230	      continue;
231	    }
232	
233	    // Paragraph (may become a setext heading).
234	    const block: Block = { kind: 'paragraph', indent, contentCol: indent, lines: [line], gap: [] };
235	    i++;
236	    while (i < lines.length && !isBlank(lines[i]!) && !startsNewBlock(lines, i)) {
237	      const underline = SETEXT_RE.exec(lines[i]!);
238	      if (underline) {
239	        block.kind = 'heading';
240	        block.level = underline[1]![0] === '=' ? 1 : 2;
241	        block.setext = true;
242	        block.lines.push(lines[i]!);
243	        i++;
244	        break;
245	      }
246	      block.lines.push(lines[i]!);
247	      i++;
248	    }
249	    // A `---` right after a paragraph is a setext h2 even though it also
250	    // matches HR_RE — handle it here since startsNewBlock stopped the loop.
251	    if (block.kind === 'paragraph' && i < lines.length && SETEXT_RE.test(lines[i]!) && HR_RE.test(lines[i]!)) {
252	      block.kind = 'heading';
253	      block.level = 2;
254	      block.setext = true;
255	      block.lines.push(lines[i]!);
256	      i++;
257	    }
258	    blocks.push(block);
259	  }
260	
261	  if (preambleGapSink) {
262	    // Blank lines before any block belong to the preamble; caller merges.
263	    blocks.unshift({
264	      kind: 'paragraph',
265	      indent: 0,
266	      contentCol: 0,
267	      lines: [],
268	      gap: preambleGapSink,
269	      level: -1, // sentinel: preamble-gap pseudo-block, consumed by caller
270	    });
271	  }
272	  return blocks;
273	}
274	
275	interface MutableNode {
276	  node: OutlineNode;
277	  children: MutableNode[];
278	}
279	
280	function toNode(m: MutableNode): OutlineNode {
281	  return { ...m.node, children: m.children.map(toNode) };
282	}
283	
284	export function parse(md: string): OutlineDoc {
285	  // ''.split('\n') is [''] — one phantom line; the empty document has none.
286	  const lines = md === '' ? [] : md.split('\n');
287	  const preamble: string[] = [];
288	  let start = 0;
289	
290	  // YAML frontmatter preamble.
291	  if (lines[0] !== undefined && /^---[ \t]*$/.test(lines[0])) {
292	    for (let i = 1; i < lines.length; i++) {
293	      if (/^(---|\.\.\.)[ \t]*$/.test(lines[i]!)) {
294	        for (let k = 0; k <= i; k++) preamble.push(lines[k]!);
295	        start = i + 1;
296	        break;
297	      }
298	    }
299	  }
300	
301	  const blocks = segment(lines, start);
302	
303	  // Fold a leading preamble-gap pseudo-block into the preamble.
304	  if (blocks[0]?.level === -1) {
305	    preamble.push(...blocks[0].gap);
306	    blocks.shift();
307	  }
308	
309	  const root: MutableNode = {
310	    node: makeNode({ kind: 'paragraph', lines: [] }), // never emitted
311	    children: [],
312	  };
313	
314	  /** Heading scope stack: root plus open headings. */
315	  const headingStack: { entry: MutableNode; level: number }[] = [
316	    { entry: root, level: 0 },
317	  ];
318	  /**
319	   * Open list-item stack within the current container. A `paragraphRoot`
320	   * entry is a paragraph currently collecting list children via the
321	   * attachment rule — only list items may attach to it.
322	   */
323	  let listStack: {
324	    entry: MutableNode;
325	    contentCol: number;
326	    indent: number;
327	    paragraphRoot?: boolean;
328	  }[] = [];
329	
330	  const container = (): MutableNode => headingStack[headingStack.length - 1]!.entry;
331	
332	  const attach = (block: Block): void => {
333	    const node = makeNode({
334	      kind: block.kind,
335	      ...(block.level !== undefined && block.kind === 'heading' ? { level: block.level } : {}),
336	      ...(block.setext ? { setext: true } : {}),
337	      ...(block.listStyle ? { listStyle: block.listStyle } : {}),
338	      lines: block.lines,
339	      trailingGap: block.gap,
340	    });
341	    const entry: MutableNode = { node, children: [] };
342	
343	    if (block.kind === 'heading') {
344	      listStack = [];
345	      while (headingStack.length > 1 && headingStack[headingStack.length - 1]!.level >= block.level!) {
346	        headingStack.pop();
347	      }
348	      container().children.push(entry);
349	      headingStack.push({ entry, level: block.level! });
350	      return;
351	    }
352	
353	    // Pop list items this block is not indented into.
354	    while (listStack.length > 0 && block.indent < listStack[listStack.length - 1]!.contentCol) {
355	      listStack.pop();
356	    }
357	
358	    if (block.kind === 'list-item') {
359	      const parent = listStack[listStack.length - 1];
360	      if (parent) {
361	        parent.entry.children.push(entry);
362	      } else {
363	        // Section level: the (provisional) attachment rule may hand the item
364	        // to an immediately preceding paragraph sibling.
365	        const siblings = container().children;
366	        const prev = siblings[siblings.length - 1];
367	        if (prev && listAttachesTo(prev.node)) {
368	          prev.children.push(entry);
369	          // Root the list stack at the paragraph's content column so later
370	          // sibling items keep attaching there.
371	          listStack = [
372	            { entry: prev, contentCol: block.indent, indent: block.indent, paragraphRoot: true },
373	          ];
374	        } else {
375	          siblings.push(entry);
376	        }
377	      }
378	      listStack.push({ entry, contentCol: block.contentCol, indent: block.indent });
379	      return;
380	    }
381	
382	    // Non-list block: child of the innermost open list item it is indented
383	    // into, else a section-level sibling (which closes any open list).
384	    // Paragraph-root entries only accept list items, never other blocks.
385	    while (listStack.length > 0 && listStack[listStack.length - 1]!.paragraphRoot) {
386	      listStack.pop();
387	    }
388	    const parent = listStack[listStack.length - 1];
389	    if (parent && block.indent >= parent.contentCol) {
390	      parent.entry.children.push(entry);
391	    } else {
392	      listStack = [];
393	      container().children.push(entry);
394	    }
395	  };
396	
397	  for (const block of blocks) attach(block);
398	
399	  return { preamble, children: root.children.map(toNode) };
400	}
